# ✅ Two Pointers: Converge from ends (sorted array)
def two_sum_sorted(arr, target):
    left, right = 0, len(arr) - 1  # ✅ Pointers at ends

    while left < right:
        sum_val = arr[left] + arr[right]
        if sum_val == target:
            return [left, right]  # ✅ Found pair
        elif sum_val < target:
            left += 1  # ✅ Move left (increase sum)
        else:
            right -= 1  # ✅ Move right (decrease sum) [web:248][web:250]

    return [-1, -1]  # ❌ Not found

