# ✅ Two Pointers: Detect duplicates in sorted token IDs
def find_duplicate_tokens(sorted_token_ids):
    left, right = 0, len(sorted_token_ids) - 1  # ✅ Opposite direction
    duplicates = []

    while left < right:
        if sorted_token_ids[left] == sorted_token_ids[right]:
            duplicates.append(sorted_token_ids[left])
            left += 1
            right -= 1
        elif sorted_token_ids[left] < sorted_token_ids[right]:
            left += 1
        else:
            right -= 1

    return duplicates  # ✅ Duplicates found

find_duplicate_tokens([1, 1, 2, 3, 3, 4])  # ✅ [1, 3] [web:250][web:257]
